import React, { useState, useRef, useEffect } from 'react';
import { TranslationStrings } from '../types.ts';
import { createChatSession } from '../services/geminiService.ts';

interface Message {
  role: 'user' | 'model';
  text: string;
}

export const KaLaAssistant: React.FC<{ lang: string; t: TranslationStrings }> = ({ lang, t }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isTyping, setIsTyping] = useState(false);
  const chatRef = useRef<any>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      if (!chatRef.current) {
        chatRef.current = createChatSession(lang as any);
      }
      const result = await chatRef.current.sendMessage({ message: userMsg });
      setMessages(prev => [...prev, { role: 'model', text: result.text || '' }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: 'Perdón, el mar está un poco picado. Inténtalo de nuevo.' }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-8 right-8 z-[100]">
      {isOpen ? (
        <div className="w-[350px] h-[500px] bg-white rounded-[2.5rem] shadow-[0_30px_60px_rgba(0,0,0,0.15)] flex flex-col overflow-hidden animate-reveal">
          {/* Header */}
          <div className="bg-[#0b3b52] p-8 text-white flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-[#CBA76B] rounded-full flex items-center justify-center text-[#0b3b52] font-black">K</div>
              <div>
                <h4 className="text-sm font-black uppercase tracking-widest">Ka'la</h4>
                <p className="text-[10px] text-white/50 uppercase tracking-tighter">Guía Local</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white/40 hover:text-white">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth={2} /></svg>
            </button>
          </div>

          {/* Messages */}
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 bg-slate-50">
            <div className="bg-white p-5 rounded-2xl rounded-tl-none shadow-sm text-sm leading-relaxed text-[#0b3b52]">
              {t.assistant.greeting}
            </div>
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-4 rounded-2xl text-sm leading-relaxed ${
                  m.role === 'user' 
                    ? 'bg-[#1f7a8c] text-white rounded-tr-none' 
                    : 'bg-white text-[#0b3b52] shadow-sm rounded-tl-none'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && <div className="text-[10px] text-[#1f7a8c] font-black uppercase animate-pulse">{t.assistant.thinking}</div>}
          </div>

          {/* Input */}
          <div className="p-6 bg-white border-t border-slate-100 flex gap-2">
            <input 
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleSend()}
              placeholder={t.assistant.placeholder}
              className="flex-1 bg-slate-50 px-5 py-3 rounded-full text-sm outline-none focus:ring-2 ring-[#CBA76B]/20 transition-all"
            />
            <button onClick={handleSend} className="w-10 h-10 bg-[#0b3b52] text-white rounded-full flex items-center justify-center shadow-lg hover:scale-110 active:scale-95 transition-all">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7" strokeWidth={3} /></svg>
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="group w-20 h-20 bg-[#0b3b52] rounded-full flex items-center justify-center shadow-2xl hover:scale-110 active:scale-95 transition-all relative overflow-hidden"
        >
          <div className="absolute inset-0 bg-[#CBA76B] translate-y-full group-hover:translate-y-0 transition-transform duration-500" />
          <svg className="w-8 h-8 text-white group-hover:text-[#0b3b52] transition-colors relative z-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path d="M8 10h.01M12 10h.01M16 10h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" strokeWidth={2} />
          </svg>
        </button>
      )}
    </div>
  );
};
